solutions.javascript:
var isPossibleToSplit = function(nums) {
    const freq = new Map();
    for (const n of nums) freq.set(n, (freq.get(n) || 0) + 1);
    for (const v of freq.values()) if (v > 2) return false;
    return true;
};
